// Backfill: divide o período em chunks de 30 dias por conta
// N8N separa array JSON em items individuais — .all() retorna N items, cada .json é 1 registro
const accounts    = $('Buscar Contas Meta').all().map(item => item.json);
const agencyItems = $('Buscar Token Meta').all();
const clientItems = $('Buscar Tokens Clientes').all();

const agencyToken = agencyItems.length > 0 ? agencyItems[0].json?.access_token : null;

const clientTokenMap = {};
for (const item of clientItems) {
  if (item.json?.client_id) clientTokenMap[item.json.client_id] = item.json.access_token;
}

const dateFrom = $('Config Backfill').item.json.DATE_FROM;
const dateTo   = $('Config Backfill').item.json.DATE_TO;

function chunkDates(from, to, chunkDays = 30) {
  const chunks = [];
  let current = new Date(from);
  const end = new Date(to);
  while (current <= end) {
    const chunkEnd = new Date(current);
    chunkEnd.setDate(chunkEnd.getDate() + chunkDays - 1);
    if (chunkEnd > end) chunkEnd.setTime(end.getTime());
    chunks.push({
      from: current.toISOString().split('T')[0],
      to:   chunkEnd.toISOString().split('T')[0]
    });
    current = new Date(chunkEnd);
    current.setDate(current.getDate() + 1);
  }
  return chunks;
}

const dateChunks = chunkDates(dateFrom, dateTo, 30);
const items = [];

for (const acc of accounts) {
  const token = clientTokenMap[acc.client_id] ?? agencyToken;
  for (const chunk of dateChunks) {
    items.push({
      json: {
        account_id:   acc.account_id,
        account_name: acc.account_name,
        client_id:    acc.client_id,
        access_token: token,
        date_from:    chunk.from,
        date_to:      chunk.to,
        supabase_url: $('Config Backfill').item.json.SUPABASE_URL,
        supabase_key: $('Config Backfill').item.json.SUPABASE_KEY
      }
    });
  }
}

console.log(`Backfill: ${items.length} requests (${accounts.length} contas × ${dateChunks.length} chunks)`);
return items;

const getAction = (arr, type) => {
  if (!Array.isArray(arr)) return 0;
  const found = arr.find(a => a.action_type === type);
  return found ? parseFloat(found.value) || 0 : 0;
};

const items = [];
for (const item of $input.all()) {
  const rows = item.json?.data ?? [];
  const loopItem = $('Loop Backfill').item.json;

  for (const row of rows) {
    const accountId = String(row.account_id ?? loopItem.account_id).replace(/^act_/, '');
    if (!row.date_start) continue;

    items.push({
      json: {
        account_id:       accountId,
        date:             row.date_start,
        spend:            parseFloat(row.spend ?? 0),
        impressions:      parseInt(row.impressions ?? 0),
        reach:            parseInt(row.reach ?? 0),
        clicks:           parseInt(row.clicks ?? 0),
        link_clicks:      parseInt(row.inline_link_clicks ?? 0),
        leads:             getAction(row.actions, 'lead'),
        conversions:       getAction(row.actions, 'offsite_conversion.fb_pixel_purchase'),
        conversion_value:  getAction(row.action_values, 'offsite_conversion.fb_pixel_purchase'),
        add_to_cart:       getAction(row.actions, 'add_to_cart'),
        initiate_checkout: getAction(row.actions, 'initiate_checkout'),
        frequency:        parseFloat(row.frequency ?? 0),
        cpm:              parseFloat(row.cpm ?? 0),
        cpc:              parseFloat(row.cpc ?? 0),
        ctr:              parseFloat(row.ctr ?? 0),
        synced_at:        new Date().toISOString(),
        _supabase_url:    loopItem.supabase_url,
        _supabase_key:    loopItem.supabase_key
      }
    });
  }
}
return items.length > 0 ? items : [{ json: { _skip: true } }];
